import { Vex } from '@vex_dev/sdk';
import { ChatFlow } from 'flowise';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  projectId: 'healthcare-flowise',
});

const flowConfig = {
  // Flowise chatflow config
  nodes: [...],
  callbacks: {
    onChatFlowExecution: async (data) => {
      const trace = await vex.trace({
        name: 'flowise-patient-query',
        input: data.input,
        metadata: { patientId: data.sessionId },
      });

      // Guard against PHI exposure
      const guard = await vex.guard({
        name: 'phi-redaction',
        input: data.output,
        rules: ['no-phi', 'no-patient-identifiers'],
      });

      if (!guard.pass) {
        throw new Error('PHI detected - blocked');
      }

      return trace.end({ output: guard.output });
    },
  },
};

