// Flowise Agent Handoff Middleware
const agentHandoffGuard = async (fromAgent: string, toAgent: string, context: any) => {
  const handoffTrace = await vex.trace({
    name: `agent-handoff-${fromAgent}-to-${toAgent}`,
    input: context,
    metadata: { timestamp: new Date().toISOString() },
  });

  // Validate context integrity
  const contextGuard = await vex.guard({
    name: 'agent-context',
    input: context,
    rules: [
      'no-phi-leakage',
      'clinical-context-preserved',
      'no-missing-allergies-medications',
    ],
  });

  if (!contextGuard.pass) {
    await handoffTrace.addEvent({
      level: 'ERROR',
      message: 'Context validation failed',
      issues: contextGuard.issues,
    });
    throw new Error('Agent handoff blocked');
  }

  return handoffTrace.end({ validatedContext: contextGuard.output });
};
